  action Open = all { open == false, open' = true, messages' = messages }
  action Send = all { open == true, messages' = messages + 1 }
  val MessagesNonNeg = messages >= 0
}

task:
Write the following file to formal/quint/gpu_alloc.qnt (exact content):

module gpu_alloc {
  var in_use: int
  var capacity: int
  action Init = all {
    in_use' = 0,
    capacity' = 8
  }
  action Allocate = all {
    in_use < capacity,
    in_use' = in_use + 1,
    capacity' = capacity
  }
  action Free = all {
    in_use > 0,
    in_use' = in_use - 1,
    capacity' = capacity
  }
  action Next = any { Allocate, Free }
  val WithinCapacity = in_use <= capacity
}

